class.description:
[PuertsScriptValue] stores a stable reference to a value that lives inside a [PuertsEnvironment]. Use it when you need to keep a script object, read properties lazily, or call a script function later from Godot code.
Use the specific [code]is_*()[/code] and [code]to_*()[/code] methods when you know the expected type. The [code]to_*()[/code] helpers perform direct typed reads from the script value.
Once the parent environment is disposed, the wrapper becomes invalid and most operations stop working.
[codeblocks]
[gdscript]
var value := env.eval("({ answer: 42, add(a, b) { return a + b; } })")
var answer := value.get_property("answer").to_int()
var sum := value.call_method("add", [10, 32]).to_int()
print(answer, sum) # 42 42
[/gdscript]
[gdscript]
var bytes := PackedByteArray([1, 2, 3, 4])
env.set_global("payload", bytes)
var payload := env.get_global("payload")
if payload.is_binary():
    print(payload.to_binary().size()) # 4
[/gdscript]
[/codeblocks]
